(game "Simple Capture"
    (players 2)
    (equipment 
        (board (square 4))
    ) 

    (rules 
        (start
            (place P1 (1 1))
            (place P2 (3 3))
        )
        (play
            (repeat (P1 P2)
                (place 
                    (destination empty)
                    (effects 
                        (capture (adjacent occupied) increment_score:true)
                    )
                )
            )
        )
        (end 
            (if (passed both) (by_score))    
        )
    )
    (rendering
        (color P1 black)
        (color P2 white)
    )
)

(game "Alternating Lines with Blocking"
    (players 2)
    (equipment 
        (board (square 5))
    ) 

    (rules 
        (play
            (repeat (P1 P2)
                (place 
                    (destination empty)
                    (result 
                        (not (and (line 5) (exists (adjacent (prev_move opponent))))))
                )
            )
        )

        (end 
            (if (line 5) (mover win))
            (if (full_board) (draw))    
        )
    )
)

(game "Island Hoppers"
    (players 2)
    (equipment 
        (board (square 5))
    ) 

    (rules 
        (play
            (repeat (P1 P2)
                (place (destination empty))
            )
        )

        (end 
            (if (and (connected (edges)) (mover_is P1)) (mover win))
            (if (and (connected (edges)) (mover_is P2)) (mover win))
            (if (full_board) (draw))    
        )
    )
    (rendering
        (color P1 black)
        (color P2 white)
    )
)

